{"code": "import json

books_file = str(var_functions.query_db_28).strip()
with open(books_file, 'r') as f:
    books_data = json.load(f)

reviews_file = str(var_functions.query_db_26).strip()
with open(reviews_file, 'r') as f:
    reviews_data = json.load(f)

ratings_by_book = {}
for review in reviews_data:
    purchase_id = review['purchase_id']
    rating = float(review['rating'])
    if purchase_id not in ratings_by_book:
        ratings_by_book[purchase_id] = []
    ratings_by_book[purchase_id].append(rating)

avg_ratings = {}
for purchase_id, ratings in ratings_by_book.items():
    avg_rating = sum(ratings) / len(ratings)
    avg_ratings[purchase_id] = {'avg_rating': avg_rating, 'count': len(ratings)}

perfect_books = {pid: info for pid, info in avg_ratings.items() if abs(info['avg_rating'] - 5.0) < 0.001}

result_books = []
for book in books_data:
    book_id = book['book_id']
    purchase_id = book_id.replace('bookid_', 'purchaseid_')
    if purchase_id in perfect_books:
        categories_str = book.get('categories', '[]')
        details_str = book.get('details', '')
        if 'Literature & Fiction' in categories_str and 'written in English' in details_str:
            author_info = book['author']
            if author_info and author_info != 'None':
                try:
                    author_dict = json.loads(author_info.replace("'", '"'))
                    author_name = author_dict.get('name', 'Unknown')
                except:
                    author_name = 'Unknown'
            else:
                author_name = 'Unknown'

            result_books.append({
                'title': book['title'],
                'author': author_name,
                'book_id': book_id,
                'rating_count': perfect_books[purchase_id]['count'],
                'details': details_str
            })

print('__RESULT__:')
print(json.dumps(result_books, indent=2))"}
